static bool ts_lex(TSLexer *lexer, TSStateId state) {
  START_LEXER();
  eof = lexer->eof(lexer);
  switch (state) {
    case 0:
      ACCEPT_TOKEN(sym_link_description);
      if (eof) ADVANCE(3);
      if (lookahead != 0 &&
          lookahead != '\n' &&
          lookahead != ']') ADVANCE(6);
      END_STATE();
    case 1:
      if (lookahead == '[') ADVANCE(4);
      if (lookahead == ']') ADVANCE(5);
      END_STATE();
    case 2:
      if (lookahead == ']') ADVANCE(1);
      if (lookahead != 0 &&
          lookahead != '\n') ADVANCE(6);
      END_STATE();
    case 3:
      ACCEPT_TOKEN(ts_builtin_sym_end);
      END_STATE();
    case 4:
      ACCEPT_TOKEN(anon_sym_RBRACK_LBRACK);
      END_STATE();
    case 5:
      ACCEPT_TOKEN(anon_sym_RBRACK_RBRACK);
      END_STATE();
    case 6:
      ACCEPT_TOKEN(sym_link_target);
      if (lookahead != 0 &&
          lookahead != '\n' &&
          lookahead != ']') ADVANCE(6);
      END_STATE();
    case 7:
      ACCEPT_TOKEN(sym_link_description);
      if (lookahead != 0 &&
          lookahead != '\n' &&
          lookahead != ']') ADVANCE(7);
      END_STATE();
    default:
      return false;
  }
}

